import json
from typing import Annotated
from fastapi import APIRouter, Depends
from fastapi.responses import StreamingResponse
from sqlalchemy.ext.asyncio import AsyncSession
from app.api.deps import get_current_user
from app.core.config import settings
from app.core.exceptions import AppError, NoAvailableUpstreamError, ProxyError, UpstreamError
from app.core.logging import logger
from app.db.base import get_session
from app.db.models import User, Upstream
from app.db.repositories.upstream_repo import UpstreamRepository
from app.schemas.openai import ChatCompletionRequest, ChatCompletionResponse
from app.services.redis import cache_mget, HEALTH_KEY
from app.services.router import rank_upstreams_by_model, get_handler

router = APIRouter(tags=["chat"])


@router.post("/chat/completions")
async def chat_completions(
    request: ChatCompletionRequest,
    user: Annotated[User, Depends(get_current_user)],
    session: Annotated[AsyncSession, Depends(get_session)],
):
    try:
        upstreams = await UpstreamRepository(session).get_enabled()
        ranked = await rank_upstreams_by_model(upstreams, request.model)

        # Filter out unhealthy upstreams
        health_keys = [HEALTH_KEY.format(u.id) for u in ranked]
        health_states = await cache_mget(health_keys)
        healthy_ranked = []
        unhealthy_ranked = []
        for u, state in zip(ranked, health_states):
            if state and state.get("status") in ("healthy", "degraded"):
                healthy_ranked.append(u)
            else:
                unhealthy_ranked.append(u)
        ranked = healthy_ranked + unhealthy_ranked

        candidates = ranked[:settings.max_retries]

        if request.stream:
            return await _stream_with_failover(request, candidates)

        return await _non_stream_with_failover(request, candidates)
    except AppError:
        raise
    except Exception as e:
        logger.error("chat_unhandled_error", exc_info=True)
        raise UpstreamError(str(e))


async def _non_stream_with_failover(
    request: ChatCompletionRequest,
    upstreams: list[Upstream],
) -> ChatCompletionResponse:
    if not upstreams:
        raise NoAvailableUpstreamError()
    errors: list[str] = []
    for upstream in upstreams:
        handler = get_handler(upstream)
        try:
            return await handler.forward(request, upstream)
        except ProxyError as e:
            errors.append(f"[{upstream.name}] {e.detail}")
            logger.warning("failover_try_next", upstream=upstream.name, model=request.model)
    raise UpstreamError("; ".join(errors))


async def _stream_with_failover(
    request: ChatCompletionRequest,
    upstreams: list[Upstream],
) -> StreamingResponse:
    if not upstreams:
        raise NoAvailableUpstreamError()
    last = upstreams[-1] if upstreams else None

    async def _stream():
        for upstream in upstreams:
            handler = get_handler(upstream)
            try:
                async for chunk in handler.forward_stream(request, upstream):
                    yield f"data: {chunk.model_dump_json()}\n\n"
                yield "data: [DONE]\n\n"
                return
            except ProxyError as e:
                logger.warning("failover_try_next_stream", upstream=upstream.name, model=request.model)
                if upstream is last:
                    yield f"data: {json.dumps({'code': 'upstream_error', 'message': e.detail})}\n\n"
            except Exception as e:
                logger.error("stream_generator_error", exc_info=True)
                yield f"data: {json.dumps({'code': 'stream_error', 'message': str(e)})}\n\n"
                if upstream is last:
                    return
        yield f"data: {json.dumps({'code': 'no_upstream', 'message': 'All upstreams exhausted'})}\n\n"

    return StreamingResponse(_stream(), media_type="text/event-stream")

from fastapi import HTTPException, status


class AppError(HTTPException):
    def __init__(self, status_code: int, detail: str, code: str = "error"):
        super().__init__(status_code=status_code, detail={"code": code, "message": detail})


class AuthError(AppError):
    def __init__(self, detail: str = "Invalid or missing API key"):
        super().__init__(status.HTTP_401_UNAUTHORIZED, detail, "auth_error")


class NotFoundError(AppError):
    def __init__(self, resource: str):
        super().__init__(status.HTTP_404_NOT_FOUND, f"{resource} not found", "not_found")


class UpstreamError(AppError):
    def __init__(self, detail: str, upstream_name: str = ""):
        msg = f"[{upstream_name}] {detail}" if upstream_name else detail
        super().__init__(status.HTTP_502_BAD_GATEWAY, msg, "upstream_error")


class NoAvailableUpstreamError(AppError):
    def __init__(self):
        super().__init__(status.HTTP_503_SERVICE_UNAVAILABLE, "No available upstream", "no_upstream")


class ProxyError(Exception):
    """内部代理异常，不继承 HTTPException，避免流式响应中被 Starlette 中间件截断连接"""
    def __init__(self, detail: str):
        self.detail = detail

from abc import ABC, abstractmethod
from typing import AsyncIterator
import httpx
from app.db.models import Upstream
from app.schemas.openai import ChatCompletionRequest, ChatCompletionResponse, ChatCompletionChunk
from app.core.exceptions import ProxyError
from app.core.logging import logger

http_client = httpx.AsyncClient(timeout=120.0)


def build_url(base_url: str, path: str) -> str:
    return f"{base_url.rstrip('/')}{path}"


def auth_header(api_key: str) -> dict[str, str]:
    return {"Authorization": f"Bearer {api_key}"}


class BaseProxyHandler(ABC):
    def _url(self, upstream: Upstream, path: str) -> str:
        return build_url(upstream.base_url, path)

    def _raise_for_http_error(self, e: Exception, upstream: Upstream) -> None:
        msg = f"[{upstream.name}] "
        if isinstance(e, httpx.HTTPStatusError):
            msg += f"HTTP {e.response.status_code}"
            logger.error("upstream_http_error", upstream=upstream.name, status=e.response.status_code)
        else:
            msg += str(e)
            logger.error("upstream_request_error", upstream=upstream.name, error=str(e))
        raise ProxyError(msg)

    @abstractmethod
    async def forward(self, request: ChatCompletionRequest, upstream: Upstream) -> ChatCompletionResponse: ...

    @abstractmethod
    async def forward_stream(self, request: ChatCompletionRequest, upstream: Upstream) -> AsyncIterator[ChatCompletionChunk]: ...

